package picod

import (
	"encoding/base64"
	"io"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
)

type FileInfo struct {
	Path     string    `json:"path"`
	Size     int64     `json:"size"`
	Mode     string    `json:"mode"`
	Modified time.Time `json:"modified"`
}

type UploadFileRequest struct {
	Path    string `json:"path"`
	Content string `json:"content"`
	Mode    string `json:"mode"`
}

type FileEntry struct {
	Name     string    `json:"name"`
	Size     int64     `json:"size"`
	Modified time.Time `json:"modified"`
	Mode     string    `json:"mode"`
	IsDir    bool      `json:"isDir"`
}

type ListFilesResponse struct {
	Files []FileEntry `json:"files"`
}

func (s *Server) UploadFileHandler(c *gin.Context) {
	contentType := c.GetHeader("Content-Type")

	if strings.HasPrefix(contentType, "multipart/form-data") {
		s.handleMultipartUpload(c)
		return
	}

	s.handleJSONBase64Upload(c)
}

func (s *Server) handleMultipartUpload(c *gin.Context) {
	path := c.PostForm("path")
	file, _, err := c.Request.FormFile("file")
	if err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}
	defer file.Close()

	modeStr := c.PostForm("mode")
	mode := os.FileMode(0644)
	if modeStr != "" {
		if m, err := strconv.ParseUint(modeStr, 8, 32); err == nil {
			mode = os.FileMode(m) & 0777
		}
	}

	destPath, err := sanitizePath(path, s.workspaceDir)
	if err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	dir := filepath.Dir(destPath)
	if err := os.MkdirAll(dir, 0755); err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	out, err := os.OpenFile(destPath, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, mode)
	if err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}
	defer out.Close()

	io.Copy(out, file)
	c.JSON(200, gin.H{"status": "uploaded", "path": path})
}

func (s *Server) handleJSONBase64Upload(c *gin.Context) {
	var req UploadFileRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	content, err := base64.StdEncoding.DecodeString(req.Content)
	if err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	mode := os.FileMode(0644)
	if req.Mode != "" {
		if m, err := strconv.ParseUint(req.Mode, 8, 32); err == nil {
			mode = os.FileMode(m) & 0777
		}
	}

	destPath, err := sanitizePath(req.Path, s.workspaceDir)
	if err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	dir := filepath.Dir(destPath)
	if err := os.MkdirAll(dir, 0755); err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	if err := os.WriteFile(destPath, content, mode); err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	c.JSON(200, gin.H{"status": "uploaded", "path": req.Path})
}

func (s *Server) ListFilesHandler(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(400, gin.H{"error": "path is required"})
		return
	}

	fullPath, err := sanitizePath(path, s.workspaceDir)
	if err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	entries, err := os.ReadDir(fullPath)
	if err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	files := make([]FileEntry, 0, len(entries))
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}

		files = append(files, FileEntry{
			Name:     entry.Name(),
			Size:     info.Size(),
			Modified: info.ModTime(),
			Mode:     info.Mode().String(),
			IsDir:    entry.IsDir(),
		})
	}

	c.JSON(200, ListFilesResponse{Files: files})
}

func (s *Server) DownloadFileHandler(c *gin.Context) {
	path := c.Param("path")

	fullPath, err := sanitizePath(path, s.workspaceDir)
	if err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	info, err := os.Stat(fullPath)
	if err != nil {
		c.JSON(404, gin.H{"error": "file not found"})
		return
	}

	if info.IsDir() {
		c.JSON(400, gin.H{"error": "cannot download directory"})
		return
	}

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Disposition", "attachment; filename="+filepath.Base(path))
	c.Header("Content-Type", "application/octet-stream")

	c.File(fullPath)
}

