		}
	}()

	timeoutCtx, cancel := context.WithTimeout(ctx, 2*time.Minute)
	defer cancel()

	select {
	case <-watchCh:
	case <-timeoutCtx.Done():
		rollback = true
		return nil, fmt.Errorf("sandbox creation timed out")
	}

	podIP, err := resolvePodIP(ctx, s.k8sClient.dynamicClient, req.Namespace, req.Name)
	if err != nil {
		rollback = true
		return nil, fmt.Errorf("failed to resolve pod IP: %w", err)
	}

	sandboxInfo := &types.SandboxInfo{
